  final integerPart = int.parse(parts[0]);
  final decimalPart = parts[1];

  String result = integerPart == 0 ? 'zero' : _intToWords(integerPart);
  result += ' point ' + decimalPart.split('').map((d) => _digitToWord(d)).join(' ');
  return result;
}

