  if (n < 0) return 'minus ${_intToWords(-n)}';
  if (n == 0) return 'zero';

  final ones = ['', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight', 'nine',
      'ten', 'eleven', 'twelve', 'thirteen', 'fourteen', 'fifteen', 'sixteen',
      'seventeen', 'eighteen', 'nineteen'];
  final tens = ['', '', 'twenty', 'thirty', 'forty', 'fifty', 'sixty', 'seventy', 'eighty', 'ninety'];

  if (n < 20) return ones[n];
  if (n < 100) {
    return tens[n ~/ 10] + (n % 10 != 0 ? '-${ones[n % 10]}' : '');
  }
  if (n < 1000) {
    return '${ones[n ~/ 100]} hundred' + (n % 100 != 0 ? ' ${_intToWords(n % 100)}' : '');
  }
  if (n < 1000000) {
    return '${_intToWords(n ~/ 1000)} thousand' + (n % 1000 != 0 ? ' ${_intToWords(n % 1000)}' : '');
  }
  if (n < 1000000000) {
    return '${_intToWords(n ~/ 1000000)} million' + (n % 1000000 != 0 ? ' ${_intToWords(n % 1000000)}' : '');
  }
  return '${_intToWords(n ~/ 1000000000)} billion' + (n % 1000000000 != 0 ? ' ${_intToWords(n % 1000000000)}' : '');
}

String _digitToWord(String d) {
  return ['zero', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight', 'nine'][int.parse(d)];
}

